import { FileType, formatFileSize } from '@nextcloud/files';
import { t } from '@nextcloud/l10n';
import { useHotKey } from '@nextcloud/vue/composables/useHotKey';
import { defineComponent } from 'vue';
import NcDateTime from '@nextcloud/vue/components/NcDateTime';
import CustomElementRender from "./CustomElementRender.vue";
import FileEntryActions from "./FileEntry/FileEntryActions.vue";
import FileEntryCheckbox from "./FileEntry/FileEntryCheckbox.vue";
import FileEntryName from "./FileEntry/FileEntryName.vue";
import FileEntryPreview from "./FileEntry/FileEntryPreview.vue";
import { useFileActions } from "../composables/useFileActions.ts";
import { useFileListWidth } from "../composables/useFileListWidth.ts";
import { useRouteParameters } from "../composables/useRouteParameters.ts";
import { useActionsMenuStore } from "../store/actionsmenu.ts";
import { useActiveStore } from "../store/active.ts";
import { useDragAndDropStore } from "../store/dragging.ts";
import { useFilesStore } from "../store/files.ts";
import { useRenamingStore } from "../store/renaming.ts";
import { useSelectionStore } from "../store/selection.ts";
import FileEntryMixin from "./FileEntryMixin.ts";
export default defineComponent({
  name: 'FileEntry',
  components: {
    CustomElementRender,
    FileEntryActions,
    FileEntryCheckbox,
    FileEntryName,
    FileEntryPreview,
    NcDateTime
  },
  mixins: [FileEntryMixin],
  props: {
    isMimeAvailable: {
      type: Boolean,
      default: false
    },
    isSizeAvailable: {
      type: Boolean,
      default: false
    }
  },
  setup() {
    const actionsMenuStore = useActionsMenuStore();
    const draggingStore = useDragAndDropStore();
    const filesStore = useFilesStore();
    const renamingStore = useRenamingStore();
    const selectionStore = useSelectionStore();
    const {
      isNarrow
    } = useFileListWidth();
    const {
      fileId: currentRouteFileId
    } = useRouteParameters();
    const {
      activeFolder,
      activeNode,
      activeView
    } = useActiveStore();
    const actions = useFileActions();
    return {
      actions,
      actionsMenuStore,
      activeFolder,
      activeNode,
      activeView,
      currentRouteFileId,
      draggingStore,
      isNarrow,
      filesStore,
      renamingStore,
      selectionStore
    };
  },
  computed: {
    /**
     * Conditionally add drag and drop listeners
     * Do not add drag start and over listeners on renaming to allow to drag and drop text
     */
    rowListeners() {
      const conditionals = this.isRenaming ? {} : {
        dragstart: this.onDragStart,
        dragover: this.onDragOver
      };
      return {
        ...conditionals,
        contextmenu: this.onRightClick,
        dragleave: this.onDragLeave,
        dragend: this.onDragEnd,
        drop: this.onDrop
      };
    },
    columns() {
      // Hide columns if the list is too small
      if (this.isNarrow || this.compact) {
        return [];
      }
      return this.activeView?.columns || [];
    },
    mime() {
      if (this.source.type === FileType.Folder) {
        return this.t('files', 'Folder');
      }
      if (!this.source.mime || this.source.mime === 'application/octet-stream') {
        return t('files', 'Unknown file type');
      }
      if (window.OC?.MimeTypeList?.names?.[this.source.mime]) {
        return window.OC.MimeTypeList.names[this.source.mime];
      }
      const baseType = this.source.mime.split('/')[0];
      const ext = this.source?.extension?.toUpperCase().replace(/^\./, '') || '';
      if (baseType === 'image') {
        return t('files', '{ext} image', {
          ext
        });
      }
      if (baseType === 'video') {
        return t('files', '{ext} video', {
          ext
        });
      }
      if (baseType === 'audio') {
        return t('files', '{ext} audio', {
          ext
        });
      }
      if (baseType === 'text') {
        return t('files', '{ext} text', {
          ext
        });
      }
      return this.source.mime;
    },
    size() {
      const size = this.source.size;
      if (size === undefined || isNaN(size) || size < 0) {
        return this.t('files', 'Pending');
      }
      return formatFileSize(size, true);
    },
    sizeOpacity() {
      const maxOpacitySize = 10 * 1024 * 1024;
      const size = this.source.size;
      if (size === undefined || isNaN(size) || size < 0) {
        return {};
      }
      const ratio = Math.round(Math.min(100, 100 * Math.pow(size / maxOpacitySize, 2)));
      return {
        color: `color-mix(in srgb, var(--color-main-text) ${ratio}%, var(--color-text-maxcontrast))`
      };
    }
  },
  created() {
    useHotKey('Enter', this.triggerDefaultAction, {
      stop: true,
      prevent: true
    });
  },
  methods: {
    formatFileSize,
    triggerDefaultAction() {
      // Don't react to the event if the file row is not active
      if (!this.isActive) {
        return;
      }
      this.defaultFileAction?.exec({
        nodes: [this.source],
        folder: this.activeFolder,
        contents: this.nodes,
        view: this.activeView
      });
    }
  }
});