import { FileType } from '@nextcloud/files';
import { translate as t } from '@nextcloud/l10n';
import { ShareType } from '@nextcloud/sharing';
import { decode } from 'blurhash';
import { computed, defineComponent, toRef } from 'vue';
import AccountGroupIcon from 'vue-material-design-icons/AccountGroup.vue';
import AccountPlusIcon from 'vue-material-design-icons/AccountPlus.vue';
import FileIcon from 'vue-material-design-icons/File.vue';
import FolderIcon from 'vue-material-design-icons/Folder.vue';
import FolderOpenIcon from 'vue-material-design-icons/FolderOpen.vue';
import KeyIcon from 'vue-material-design-icons/Key.vue';
import LinkIcon from 'vue-material-design-icons/Link.vue';
import NetworkIcon from 'vue-material-design-icons/NetworkOutline.vue';
import PlayCircleIcon from 'vue-material-design-icons/PlayCircle.vue';
import TagIcon from 'vue-material-design-icons/Tag.vue';
import CollectivesIcon from "./CollectivesIcon.vue";
import FavoriteIcon from "./FavoriteIcon.vue";
import RecentlyCreatedIcon from "./RecentlyCreatedIcon.vue";
import { usePreviewImage } from "../../composables/usePreviewImage.ts";
import { isLivePhoto } from "../../services/LivePhotos.ts";
import { useUserConfigStore } from "../../store/userconfig.ts";
import { logger } from "../../utils/logger.ts";
export default defineComponent({
  name: 'FileEntryPreview',
  components: {
    AccountGroupIcon,
    AccountPlusIcon,
    CollectivesIcon,
    FavoriteIcon,
    FileIcon,
    FolderIcon,
    FolderOpenIcon,
    KeyIcon,
    LinkIcon,
    NetworkIcon,
    TagIcon,
    RecentlyCreatedIcon
  },
  props: {
    source: {
      type: Object,
      required: true
    },
    dragover: {
      type: Boolean,
      default: false
    },
    gridMode: {
      type: Boolean,
      default: false
    }
  },
  setup(props) {
    const userConfigStore = useUserConfigStore();
    const previewUrl = usePreviewImage(toRef(props, 'source'), computed(() => ({
      crop: userConfigStore.userConfig.crop_image_previews === true,
      size: props.gridMode ? 128 : 32
    })));
    return {
      userConfigStore,
      previewUrl
    };
  },
  data() {
    return {
      backgroundFailed: undefined,
      backgroundLoaded: false
    };
  },
  computed: {
    isFavorite() {
      return this.source.attributes.favorite === 1;
    },
    isRecentlyCreated() {
      if (!this.source.crtime) {
        return false;
      }
      const oneDayAgo = new Date();
      oneDayAgo.setDate(oneDayAgo.getDate() - 1);
      return this.source.crtime > oneDayAgo;
    },
    isRecentView() {
      return this.$route?.params?.view === 'recent';
    },
    userConfig() {
      return this.userConfigStore.userConfig;
    },
    fileOverlay() {
      if (isLivePhoto(this.source)) {
        return PlayCircleIcon;
      }
      return null;
    },
    folderOverlay() {
      if (this.source.type !== FileType.Folder) {
        return null;
      }
      // Encrypted folders
      if (this.source?.attributes?.['is-encrypted'] === 1) {
        return KeyIcon;
      }
      // System tags
      if (this.source?.attributes?.['is-tag']) {
        return TagIcon;
      }
      // Link and mail shared folders
      const shareTypes = Object.values(this.source?.attributes?.['share-types'] || {}).flat();
      if (shareTypes.some(type => type === ShareType.Link || type === ShareType.Email)) {
        return LinkIcon;
      }
      // Shared folders
      if (shareTypes.length > 0) {
        return AccountPlusIcon;
      }
      switch (this.source?.attributes?.['mount-type']) {
        case 'external':
        case 'external-session':
          return NetworkIcon;
        case 'group':
          return AccountGroupIcon;
        case 'collective':
          return CollectivesIcon;
        case 'shared':
          return AccountPlusIcon;
      }
      return null;
    },
    hasBlurhash() {
      return this.source.attributes['metadata-blurhash'] !== undefined;
    }
  },
  mounted() {
    if (this.hasBlurhash && this.$refs.canvas) {
      this.drawBlurhash();
    }
  },
  methods: {
    // Called from FileEntry
    reset() {
      // Reset background state to cancel any ongoing requests
      this.backgroundFailed = undefined;
      this.backgroundLoaded = false;
      const previewImg = this.$refs.previewImg;
      if (previewImg) {
        previewImg.src = '';
      }
    },
    onBackgroundLoad() {
      this.backgroundFailed = false;
      this.backgroundLoaded = true;
    },
    onBackgroundError(event) {
      // Do not fail if we just reset the background
      if (event.target?.src === '') {
        return;
      }
      this.backgroundFailed = true;
      this.backgroundLoaded = false;
    },
    drawBlurhash() {
      const canvas = this.$refs.canvas;
      const width = canvas.width;
      const height = canvas.height;
      const pixels = decode(this.source.attributes['metadata-blurhash'], width, height);
      const ctx = canvas.getContext('2d');
      if (ctx === null) {
        logger.error('Cannot create context for blurhash canvas');
        return;
      }
      const imageData = ctx.createImageData(width, height);
      imageData.data.set(pixels);
      ctx.putImageData(imageData, 0, 0);
    },
    t
  }
});