import { showError } from '@nextcloud/dialogs';
import { FileType, NodeStatus } from '@nextcloud/files';
import { translate as t } from '@nextcloud/l10n';
import { basename } from '@nextcloud/paths';
import { defineComponent, inject } from 'vue';
import NcTextField from '@nextcloud/vue/components/NcTextField';
import { useFileListWidth } from "../../composables/useFileListWidth.ts";
import { useActiveStore } from "../../store/active.ts";
import { useRenamingStore } from "../../store/renaming.ts";
import { useUserConfigStore } from "../../store/userconfig.ts";
import { getFilenameValidity } from "../../utils/filenameValidity.ts";
import { logger } from "../../utils/logger.ts";
export default defineComponent({
  name: 'FileEntryName',
  components: {
    NcTextField
  },
  props: {
    /**
     * The filename without extension
     */
    basename: {
      type: String,
      required: true
    },
    /**
     * The extension of the filename
     */
    extension: {
      type: String,
      required: true
    },
    source: {
      type: Object,
      required: true
    }
  },
  setup() {
    // The file list is guaranteed to be only shown with active view - thus we can set the `loaded` flag
    const {
      isNarrow
    } = useFileListWidth();
    const renamingStore = useRenamingStore();
    const userConfigStore = useUserConfigStore();
    const {
      activeFolder,
      activeView
    } = useActiveStore();
    const defaultFileAction = inject('defaultFileAction');
    return {
      activeFolder,
      activeView,
      defaultFileAction,
      isNarrow,
      renamingStore,
      userConfigStore
    };
  },
  computed: {
    isRenaming() {
      return this.renamingStore.renamingNode === this.source;
    },
    isRenamingSmallScreen() {
      return this.isRenaming && this.isNarrow;
    },
    newName: {
      get() {
        return this.renamingStore.newNodeName;
      },
      set(newName) {
        this.renamingStore.newNodeName = newName;
      }
    },
    renameLabel() {
      const matchLabel = {
        [FileType.File]: t('files', 'Filename'),
        [FileType.Folder]: t('files', 'Folder name')
      };
      return matchLabel[this.source.type];
    },
    linkTo() {
      if (this.source.status === NodeStatus.FAILED) {
        return {
          is: 'span',
          params: {
            title: t('files', 'This node is unavailable')
          }
        };
      }
      if (this.defaultFileAction) {
        const displayName = this.defaultFileAction.displayName({
          nodes: [this.source],
          view: this.activeView,
          folder: this.activeFolder,
          contents: []
        });
        return {
          is: 'button',
          params: {
            'aria-label': displayName,
            title: displayName,
            tabindex: '0'
          }
        };
      }
      // nothing interactive here, there is no default action
      // so if not even the download action works we only can show the list entry
      return {
        is: 'span'
      };
    }
  },
  watch: {
    /**
     * If renaming starts, select the filename
     * in the input, without the extension.
     *
     * @param renaming
     */
    isRenaming: {
      immediate: true,
      handler(renaming) {
        if (renaming) {
          this.startRenaming();
        }
      }
    },
    newName() {
      // Check validity of the new name
      const newName = this.newName.trim?.() || '';
      const input = this.$refs.renameInput?.$el.querySelector('input');
      if (!input) {
        return;
      }
      let validity = getFilenameValidity(newName);
      // Checking if already exists
      if (validity === '' && this.checkIfNodeExists(newName)) {
        validity = t('files', 'Another entry with the same name already exists.');
      }
      this.$nextTick(() => {
        if (this.isRenaming) {
          input.setCustomValidity(validity);
          input.reportValidity();
        }
      });
    }
  },
  methods: {
    checkIfNodeExists(name) {
      const sources = this.activeFolder?._children || [];
      return sources.some(sourceName => basename(sourceName) === name);
    },
    startRenaming() {
      this.$nextTick(() => {
        // Using split to get the true string length
        const input = this.$refs.renameInput?.$el.querySelector('input');
        if (!input) {
          logger.error('Could not find the rename input');
          return;
        }
        input.focus();
        const length = this.source.basename.length - (this.source.extension ?? '').length;
        input.setSelectionRange(0, length);
        // Trigger a keyup event to update the input validity
        input.dispatchEvent(new Event('keyup'));
      });
    },
    stopRenaming() {
      if (!this.isRenaming) {
        return;
      }
      // Reset the renaming store
      this.renamingStore.$reset();
    },
    // Rename and move the file
    async onRename() {
      const newName = this.newName.trim?.() || '';
      const form = this.$refs.renameForm;
      if (!form.checkValidity()) {
        showError(t('files', 'Invalid filename.') + ' ' + getFilenameValidity(newName));
        return;
      }
      const oldName = this.source.basename;
      if (newName === oldName) {
        this.stopRenaming();
        return;
      }
      try {
        const status = await this.renamingStore.rename();
        if (status) {
          this.$nextTick(() => {
            const nameContainer = this.$refs.basename;
            nameContainer?.focus();
          });
        } else {
          // Was cancelled - meaning the renaming state is just reset
        }
      } catch (error) {
        logger.error(error);
        showError(error.message);
        // And ensure we reset to the renaming state
        this.startRenaming();
      }
    },
    t
  }
});