import { showError } from '@nextcloud/dialogs';
import { FileType, Folder, getSidebar, Permission, View } from '@nextcloud/files';
import { n, t } from '@nextcloud/l10n';
import { useHotKey } from '@nextcloud/vue/composables/useHotKey';
import { computed, defineComponent } from 'vue';
import FileEntry from "./FileEntry.vue";
import FileEntryGrid from "./FileEntryGrid.vue";
import FileListFilterChips from "./FileListFilter/FileListFilterChips.vue";
import FileListFilterToSearch from "./FileListFilter/FileListFilterToSearch.vue";
import FilesListHeader from "./FilesListHeader.vue";
import FilesListTableFooter from "./FilesListTableFooter.vue";
import FilesListTableHeader from "./FilesListTableHeader.vue";
import FilesListTableHeaderActions from "./FilesListTableHeaderActions.vue";
import VirtualList from "./VirtualList.vue";
import { useEnabledFileActions } from "../composables/useFileActions.ts";
import { useFileListHeaders } from "../composables/useFileListHeaders.ts";
import { useFileListWidth } from "../composables/useFileListWidth.ts";
import { useRouteParameters } from "../composables/useRouteParameters.ts";
import { useActiveStore } from "../store/active.ts";
import { useSelectionStore } from "../store/selection.ts";
import { useUserConfigStore } from "../store/userconfig.ts";
import { logger } from "../utils/logger.ts";
export default defineComponent({
  name: 'FilesListVirtual',
  components: {
    FileListFilterChips,
    FileListFilterToSearch,
    FilesListHeader,
    FilesListTableFooter,
    FilesListTableHeader,
    VirtualList,
    FilesListTableHeaderActions
  },
  props: {
    currentView: {
      type: View,
      required: true
    },
    currentFolder: {
      type: Folder,
      required: true
    },
    nodes: {
      type: Array,
      required: true
    },
    summary: {
      type: String,
      required: true
    }
  },
  setup(props) {
    const sidebar = getSidebar();
    const activeStore = useActiveStore();
    const selectionStore = useSelectionStore();
    const userConfigStore = useUserConfigStore();
    const {
      isNarrow,
      isWide
    } = useFileListWidth();
    const {
      fileId,
      openDetails,
      openFile
    } = useRouteParameters();
    const isMimeAvailable = computed(() => {
      if (!userConfigStore.userConfig.show_mime_column) {
        return false;
      }
      if (!isWide.value) {
        return false; // only show on wide screens
      }
      return props.nodes.some(node => node.mime !== undefined || node.mime !== 'application/octet-stream');
    });
    const isMtimeAvailable = computed(() => {
      // Hide mtime column on narrow screens
      if (isNarrow.value) {
        return false; // hide on narrow screens
      }
      return props.nodes.some(node => node.mtime !== undefined);
    });
    const isSizeAvailable = computed(() => {
      // Hide size column on narrow screens
      if (isNarrow.value) {
        return false; // hide on narrow screens
      }
      return props.nodes.some(node => node.size !== undefined);
    });
    return {
      fileId,
      headers: useFileListHeaders(),
      isSizeAvailable,
      isMtimeAvailable,
      isMimeAvailable,
      openDetails,
      openFile,
      sidebar,
      activeStore,
      selectionStore,
      userConfigStore,
      n,
      t
    };
  },
  data() {
    return {
      FileEntry,
      FileEntryGrid,
      scrollToIndex: 0
    };
  },
  computed: {
    userConfig() {
      return this.userConfigStore.userConfig;
    },
    cantUpload() {
      return this.currentFolder && (this.currentFolder.permissions & Permission.CREATE) === 0;
    },
    isQuotaExceeded() {
      return this.currentFolder?.attributes?.['quota-available-bytes'] === 0;
    },
    caption() {
      const defaultCaption = t('files', 'List of files and folders.');
      const viewCaption = this.currentView.caption || defaultCaption;
      const cantUploadCaption = this.cantUpload ? t('files', 'You do not have permission to upload or create files here.') : null;
      const quotaExceededCaption = this.isQuotaExceeded ? t('files', 'You have used your space quota and cannot upload files anymore.') : null;
      const sortableCaption = t('files', 'Column headers with buttons are sortable.');
      const virtualListNote = t('files', 'This list is not fully rendered for performance reasons. The files will be rendered as you navigate through the list.');
      return [viewCaption, cantUploadCaption, quotaExceededCaption, sortableCaption, virtualListNote].filter(Boolean).join('\n');
    },
    selectedNodes() {
      return this.selectionStore.selected;
    },
    isNoneSelected() {
      return this.selectedNodes.length === 0;
    },
    isEmpty() {
      return this.nodes.length === 0;
    }
  },
  watch: {
    // If nodes gets populated and we have a fileId,
    // an openFile or openDetails, we fire the appropriate actions.
    isEmpty() {
      this.handleOpenQueries();
    },
    fileId() {
      this.handleOpenQueries();
    },
    openFile() {
      this.handleOpenQueries();
    },
    openDetails() {
      this.handleOpenQueries();
    }
  },
  created() {
    useHotKey('Escape', this.unselectFile, {
      stop: true,
      prevent: true
    });
    useHotKey(['ArrowUp', 'ArrowDown', 'ArrowLeft', 'ArrowRight'], this.onKeyDown, {
      stop: true,
      prevent: true
    });
  },
  mounted() {
    // Add events on parent to cover both the table and DragAndDrop notice
    const mainContent = window.document.querySelector('main.app-content');
    mainContent.addEventListener('dragover', this.onDragOver);
  },
  beforeUnmount() {
    const mainContent = window.document.querySelector('main.app-content');
    mainContent.removeEventListener('dragover', this.onDragOver);
  },
  methods: {
    handleOpenQueries() {
      // If the list is empty, or we don't have a fileId,
      // there's nothing to be done.
      if (this.isEmpty || this.fileId === null) {
        return;
      }
      logger.debug('FilesListVirtual: checking for requested fileId, openFile or openDetails', {
        nodes: this.nodes,
        fileId: this.fileId,
        openFile: this.openFile,
        openDetails: this.openDetails
      });
      if (this.openFile) {
        this.handleOpenFile(this.fileId);
      }
      if (this.openDetails) {
        this.openSidebarForFile(this.fileId);
      }
      if (this.fileId) {
        const node = this.nodes.find(node => node.fileid === this.fileId);
        if (node) {
          this.activeStore.activeNode = node;
          this.scrollToFile(this.fileId, false);
        }
      }
    },
    openSidebarForFile(fileId) {
      // Open the sidebar for the given URL fileid
      // iif we just loaded the app.
      const node = this.nodes.find(n => n.fileid === fileId);
      if (node && this.sidebar.available) {
        logger.debug('Opening sidebar on file ' + node.path, {
          node
        });
        this.sidebar.open(node);
      } else {
        logger.warn(`Failed to open sidebar on file ${fileId}, file isn't cached yet !`, {
          fileId,
          node
        });
      }
    },
    scrollToFile(fileId, warn = true) {
      if (fileId) {
        // Do not uselessly scroll to the top of the list.
        if (fileId === this.currentFolder.fileid) {
          return;
        }
        const index = this.nodes.findIndex(node => node.fileid === fileId);
        if (warn && index === -1 && fileId !== this.currentFolder.fileid) {
          showError(t('files', 'File not found'));
        }
        this.scrollToIndex = Math.max(0, index);
        logger.debug('Scrolling to file ' + fileId, {
          fileId,
          index
        });
      }
    },
    /**
     * Unselect the current file and clear open parameters from the URL
     */
    unselectFile() {
      const query = {
        ...this.$route.query
      };
      delete query.openfile;
      delete query.opendetails;
      this.activeStore.activeNode = this.currentFolder;
    },
    /**
     * Handle opening a file (e.g. by ?openfile=true)
     *
     * @param fileId File to open
     */
    async handleOpenFile(fileId) {
      const node = this.nodes.find(n => n.fileid === fileId);
      if (node === undefined) {
        return;
      }
      if (node.type === FileType.File) {
        const actions = useEnabledFileActions({
          nodes: [node],
          view: this.currentView,
          folder: this.currentFolder,
          contents: this.nodes
        });
        const defaultAction = actions.value.find(action => action.id !== 'download' && !!action.default);
        // Some file types do not have a default action (e.g. they can only be downloaded)
        // So if there is an enabled default action, so execute it
        if (defaultAction) {
          logger.debug('Opening file ' + node.path, {
            node
          });
          return await defaultAction.exec({
            nodes: [node],
            view: this.currentView,
            folder: this.currentFolder,
            contents: this.nodes
          });
        }
      }
      // The file is either a folder or has no default action other than downloading
      // in this case we need to open the details instead and remove the route from the history
      logger.debug('Ignore `openfile` query and replacing with `opendetails` for ' + node.path, {
        node
      });
      window.OCP.Files.Router.goToRoute(null, window.OCP.Files.Router.params, {
        ...this.$route.query,
        openfile: undefined,
        opendetails: ''
      }, true);
    },
    onDragOver(event) {
      // Detect if we're only dragging existing files or not
      const isForeignFile = event.dataTransfer?.types.includes('Files');
      if (isForeignFile) {
        // Only handle uploading of existing Nextcloud files
        // See DragAndDropNotice for handling of foreign files
        return;
      }
      event.preventDefault();
      event.stopPropagation();
      const tableElement = this.$refs.table.$el;
      const tableTop = tableElement.getBoundingClientRect().top;
      const tableBottom = tableTop + tableElement.getBoundingClientRect().height;
      // If reaching top, scroll up. Using 100 because of the floating header
      if (event.clientY < tableTop + 100) {
        tableElement.scrollTop = tableElement.scrollTop - 25;
        return;
      }
      // If reaching bottom, scroll down
      if (event.clientY > tableBottom - 50) {
        tableElement.scrollTop = tableElement.scrollTop + 25;
      }
    },
    onKeyDown(event) {
      if (this.isEmpty) {
        return;
      }
      if (event.key !== 'ArrowUp' && event.key !== 'ArrowDown' && (!this.userConfig.grid_view || event.key !== 'ArrowLeft' && event.key !== 'ArrowRight')) {
        // not an arrow key we handle
        return;
      }
      if (!this.fileId || this.fileId === this.currentFolder.fileid) {
        // no active node so use either first or last node
        const index = event.key === 'ArrowUp' || event.key === 'ArrowLeft' ? this.nodes.length - 1 : 0;
        this.setActiveNode(this.nodes[index]);
      }
      const index = this.nodes.findIndex(node => node.fileid === this.fileId) ?? 0;
      // Up and down arrow keys
      if (event.key === 'ArrowUp' || event.key === 'ArrowDown') {
        const columnCount = this.$refs.table?.columnCount ?? 1;
        const nextIndex = event.key === 'ArrowUp' ? index - columnCount : index + columnCount;
        if (nextIndex < 0 || nextIndex >= this.nodes.length) {
          return;
        }
        const nextNode = this.nodes[nextIndex];
        if (nextNode && nextNode?.fileid) {
          this.setActiveNode(nextNode);
          return;
        }
      }
      // if grid mode, left and right arrow keys
      if (this.userConfig.grid_view && (event.key === 'ArrowLeft' || event.key === 'ArrowRight')) {
        const nextIndex = event.key === 'ArrowLeft' ? index - 1 : index + 1;
        if (nextIndex < 0 || nextIndex >= this.nodes.length) {
          return;
        }
        const nextNode = this.nodes[nextIndex];
        if (nextNode && nextNode?.fileid) {
          this.setActiveNode(nextNode);
          return;
        }
      }
    },
    async setActiveNode(node) {
      logger.debug('Navigating to file ' + node.path, {
        node,
        fileid: node.fileid
      });
      this.scrollToFile(node.fileid);
      // Remove openfile and opendetails from the URL
      const query = {
        ...this.$route.query
      };
      delete query.openfile;
      delete query.opendetails;
      await this.$router.replace({
        ...this.$route,
        query
      });
      // set the new file as active
      this.activeStore.activeNode = node;
    }
  }
});